type labelEntry struct {
	firstSeen time.Time
	lastSeen  time.Time
}

type CardinalityLimiter struct {
	mu            sync.RWMutex
	labelValues   map[string]map[string]*labelEntry // metric_name -> label_value -> entry
	maxPerMetric  int
	overflowCount *prometheus.CounterVec
}

func NewCardinalityLimiter(maxPerMetric int) *CardinalityLimiter {
	overflowCounter := prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "metrics_cardinality_overflow_total",
			Help: "Number of times a label value was rejected due to cardinality limits",
		},
		[]string{"metric_name"},
	)
	prometheus.MustRegister(overflowCounter)

	cl := &CardinalityLimiter{
		labelValues:   make(map[string]map[string]*labelEntry),
		maxPerMetric:  maxPerMetric,
		overflowCount: overflowCounter,
	}

	go cl.cleanupLoop()

	return cl
}

func (cl *CardinalityLimiter) cleanupLoop() {
	ticker := time.NewTicker(labelCleanupInterval)
	defer ticker.Stop()
	for range ticker.C {
		cl.cleanup()
	}
}

func (cl *CardinalityLimiter) cleanup() {
	cl.mu.Lock()
	defer cl.mu.Unlock()

	cutoff := time.Now().Add(-maxLabelAge)
	for metric, values := range cl.labelValues {
		for val, entry := range values {
			if entry.lastSeen.Before(cutoff) {
				delete(values, val)
			}
		}
		if len(values) == 0 {
			delete(cl.labelValues, metric)
		}
	}
}

func (cl *CardinalityLimiter) AllowLabelValue(metricName, labelValue string) (string, bool) {
	sanitized := sanitizeLabelValue(labelValue)
	if sanitized == "" {
		return "__invalid__", false
	}

	cl.mu.Lock()
	defer cl.mu.Unlock()

	if cl.labelValues[metricName] == nil {
		cl.labelValues[metricName] = make(map[string]*labelEntry)
	}

	values := cl.labelValues[metricName]

	if entry, exists := values[sanitized]; exists {
		entry.lastSeen = time.Now()
		return sanitized, true
	}

	if len(values) >= cl.maxPerMetric {
		cl.overflowCount.WithLabelValues(metricName).Inc()
		return "__overflow__", false
	}

	values[sanitized] = &labelEntry{
		firstSeen: time.Now(),
		lastSeen:  time.Now(),
	}
	return sanitized, true
}

func (cl *CardinalityLimiter) GetCardinalityStats() map[string]int {
	cl.mu.RLock()
	defer cl.mu.RUnlock()

	stats := make(map[string]int)
	for metric, values := range cl.labelValues {
		stats[metric] = len(values)
	}
	return stats
}

func sanitizeLabelValue(value string) string {
	value = strings.TrimSpace(value)

	if len(value) == 0 {
		return ""
	}

	if len(value) > maxLabelLength {
		value = value[:maxLabelLength]
	}

	if !allowedLabelPattern.MatchString(value) {
		return ""
	}

	return value
}

func normalizeEndpoint(endpoint string) string {
	endpoint = strings.TrimSpace(endpoint)
	endpoint = strings.ToLower(endpoint)

	if endpoint == "" {
		return "__unknown__"
	}

	if !strings.HasPrefix(endpoint, "/") {
		endpoint = "/" + endpoint
	}

	// Prevent path traversal
	if strings.Contains(endpoint, "..") {
		return "__invalid__"
	}

	if allowedEndpoints[endpoint] {
		return endpoint
	}

	// Try to match a prefix for parameterized routes
	parts := strings.Split(endpoint, "/")
	if len(parts) > 3 {
		// Normalize deep paths to prevent cardinality explosion from path params
		base := strings.Join(parts[:3], "/")
		if allowedEndpoints[base] {
			return base
		}
	}

	return "__other__"
}

func normalizeMethod(method string) string {
	method = strings.ToUpper(strings.TrimSpace(method))
	if allowedMethods[method] {
		return method
	}
	return "__other__"
}

func normalizeStatusCode(code int) string {
	switch {
	case code >= 200 && code < 300:
		return "2xx"
	case code >= 300 && code < 400:
		return "3xx"
	case code >= 400 && code < 500:
		return "4xx"
	case code >= 500 && code < 600:
		return "5xx"
	default:
		return "other"
	}
}

