func (m *SafeMetrics) safeUserID(userID string) string {
	sanitized, allowed := m.limiter.AllowLabelValue("user_id", userID)
	if !allowed {
		return sanitized // "__overflow__" or "__invalid__"
	}
	return sanitized
}

func (m *SafeMetrics) RecordRequest(userID, method, endpoint string, statusCode int, duration time.Duration, reqSize, respSize int64) {
	safeMethod := normalizeMethod(method)
	safeEndpoint := normalizeEndpoint(endpoint)
	safeStatus := normalizeStatusCode(statusCode)
	safeUser := m.safeUserID(userID)

	m.requestsTotal.WithLabelValues(safeMethod, safeEndpoint, safeStatus).Inc()
	m.requestDuration.WithLabelValues(safeMethod, safeEndpoint).Observe(duration.Seconds())
	m.requestSize.WithLabelValues(safeMethod, safeEndpoint).Observe(float64(reqSize))
	m.responseSize.WithLabelValues(safeMethod, safeEndpoint).Observe(float64(respSize))

	m.userRequestsTotal.WithLabelValues(safeUser, safeMethod, safeEndpoint).Inc()
	m.userRequestDuration.WithLabelValues(safeUser, safeMethod).Observe(duration.Seconds())

	if statusCode >= 400 {
		errorType := "client_error"
		if statusCode >= 500 {
			errorType = "server_error"
		}
		m.errorsTotal.WithLabelValues(safeMethod, safeEndpoint, errorType).Inc()
		m.userErrorsTotal.WithLabelValues(safeUser, errorType).Inc()
	}
}

func (m *SafeMetrics) TrackActiveRequest(userID, method, endpoint string) func() {
	safeMethod := normalizeMethod(method)
	safeEndpoint := normalizeEndpoint(endpoint)
	safeUser := m.safeUserID(userID)

	m.activeRequests.WithLabelValues(safeMethod, safeEndpoint).Inc()
	m.userActiveRequests.WithLabelValues(safeUser).Inc()

	return func() {
		m.activeRequests.WithLabelValues(safeMethod, safeEndpoint).Dec()
		m.userActiveRequests.WithLabelValues(safeUser).Dec()
	}
}

type responseWriter struct {
	http.ResponseWriter
	statusCode int
	bytesWritten int64
}

func newResponseWriter(w http.ResponseWriter) *responseWriter {
	return &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func (rw *responseWriter) Write(b []byte) (int, error) {
	n, err := rw.ResponseWriter.Write(b)
	rw.bytesWritten += int64(n)
	return n, err
}

func metricsMiddleware(metrics *SafeMetrics, next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = "__anonymous__"
		}

		done := metrics.TrackActiveRequest(userID, r.Method, r.URL.Path)
		defer done()

		start := time.Now()
		rw := newResponseWriter(w)

		next.ServeHTTP(rw, r)

		duration := time.Since(start)
		metrics.RecordRequest(
			userID,
			r.Method,
			r.URL.Path,
			rw.statusCode,
			duration,
			r.ContentLength,
			rw.bytesWritten,
		)
	})
}

